import{_ as n,o as a,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Account aanmaken","description":"","frontmatter":{},"headers":[],"relativePath":"nl/getting-started/create-account.md","filePath":"nl/getting-started/create-account.md"}'),i={name:"nl/getting-started/create-account.md"};function o(l,e,s,d,g,c){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="account-aanmaken" tabindex="-1">Account aanmaken <a class="header-anchor" href="#account-aanmaken" aria-label="Permalink to &quot;Account aanmaken&quot;">​</a></h1><p>Aan de slag gaan met MyCompanyDesk duurt maar een paar minuten.</p><h2 id="registreren" tabindex="-1">Registreren <a class="header-anchor" href="#registreren" aria-label="Permalink to &quot;Registreren&quot;">​</a></h2><ol><li>Ga naar <a href="https://app.mycompanydesk.com" target="_blank" rel="noreferrer">app.mycompanydesk.com</a> en klik op <strong>Registreren</strong></li><li>Kies een van de volgende methoden: <ul><li><strong>E-mail en wachtwoord</strong> — Vul je naam, e-mailadres en een veilig wachtwoord in</li><li><strong>Google</strong> — Log in met je Google-account</li><li><strong>Microsoft/Outlook</strong> — Log in met je Microsoft-account</li></ul></li><li>Als je je met e-mail hebt geregistreerd, controleer dan je inbox op een <strong>verificatie-e-mail</strong> en klik op de link om je account te bevestigen</li></ol><h2 id="werkruimte-aanmaken-of-deelnemen" tabindex="-1">Werkruimte aanmaken of deelnemen <a class="header-anchor" href="#werkruimte-aanmaken-of-deelnemen" aria-label="Permalink to &quot;Werkruimte aanmaken of deelnemen&quot;">​</a></h2><p>Na het registreren heb je twee opties:</p><h3 id="een-nieuwe-werkruimte-aanmaken" tabindex="-1">Een nieuwe werkruimte aanmaken <a class="header-anchor" href="#een-nieuwe-werkruimte-aanmaken" aria-label="Permalink to &quot;Een nieuwe werkruimte aanmaken&quot;">​</a></h3><p>Als je de eerste persoon van je bedrijf bent, maak dan een nieuwe werkruimte aan:</p><ol><li>Vul je <strong>bedrijfsnaam</strong> in</li><li>Kies je gewenste <strong>taal</strong></li><li>Klik op <strong>Werkruimte aanmaken</strong></li></ol><p>Dit maakt een lege werkruimte aan waar je je bedrijfsinformatie, klanten en facturen kunt toevoegen.</p><h3 id="deelnemen-aan-een-bestaande-werkruimte" tabindex="-1">Deelnemen aan een bestaande werkruimte <a class="header-anchor" href="#deelnemen-aan-een-bestaande-werkruimte" aria-label="Permalink to &quot;Deelnemen aan een bestaande werkruimte&quot;">​</a></h3><p>Als een collega al een werkruimte heeft opgezet:</p><ol><li>Vraag hen om je een <strong>uitnodiging</strong> te sturen via Instellingen &gt; Team</li><li>Klik op de uitnodigingslink in je e-mail</li><li>Accepteer de uitnodiging om deel te nemen aan hun werkruimte</li></ol><p>Je kunt lid zijn van meerdere werkruimten en ertussen wisselen via je accountmenu.</p><h2 id="kies-je-dashboardprofiel" tabindex="-1">Kies je dashboardprofiel <a class="header-anchor" href="#kies-je-dashboardprofiel" aria-label="Permalink to &quot;Kies je dashboardprofiel&quot;">​</a></h2><p>Bij je eerste aanmelding zie je de <strong>onboardingkaart</strong> op je dashboard. MyCompanyDesk biedt dashboardprofielen die zijn afgestemd op verschillende rollen:</p><ul><li><strong>Eigenaar / Directeur</strong> — Financieel overzicht op hoog niveau en cashflow</li><li><strong>Boekhouder / Accountant</strong> — BTW-compliance, audittrails, periodeversluitingen</li><li><strong>Freelancer</strong> — Vereenvoudigd overzicht gericht op facturatie en inkomsten</li><li><strong>Projectgericht</strong> — Focus op projectwinstgevendheid en tijdregistratie</li><li><strong>Debiteuren (Facturatie)</strong> — Factuurstatistieken en betalingsopvolging</li><li><strong>Crediteuren (Inkoop)</strong> — Uitgaven bijhouden en leveranciersbeheer</li><li><strong>BTW-compliance</strong> — BTW-berekeningen en deadlines</li><li><strong>Groei / Operations</strong> — Omzettrends en klantenwerving</li></ul><p>Je kunt je dashboardprofiel op elk moment wijzigen via de dashboardinstellingen.</p><h2 id="voltooi-de-onboardingchecklist" tabindex="-1">Voltooi de onboardingchecklist <a class="header-anchor" href="#voltooi-de-onboardingchecklist" aria-label="Permalink to &quot;Voltooi de onboardingchecklist&quot;">​</a></h2><p>De onboardingkaart begeleidt je door drie belangrijke installatiestappen:</p><ol><li><strong>Stel je bedrijfsinformatie in</strong> — Voeg je bedrijfsnaam, adres, BTW-nummer en bankgegevens toe</li><li><strong>Voeg je eerste klant toe</strong> — Maak een klantrecord aan om te beginnen met factureren</li><li><strong>Maak je eerste factuur</strong> — Verstuur je eerste professionele factuur</li></ol><p>De kaart verdwijnt automatisch zodra je deze stappen hebt voltooid, of je kunt hem handmatig sluiten.</p><h2 id="volgende-stappen" tabindex="-1">Volgende stappen <a class="header-anchor" href="#volgende-stappen" aria-label="Permalink to &quot;Volgende stappen&quot;">​</a></h2><p>Nu je account klaar is, <a href="/nl/getting-started/company-setup">stel je bedrijfsinformatie in</a>.</p>',24)])])}const k=n(i,[["render",o]]);export{u as __pageData,k as default};
